function getPosterPlayers() {
  const posOrder = ['PG','SG','SF','PF','C'];
  return posOrder.map(pos => {
    const p = game.slots[pos];
    if (!p) return null;
    const colors = TEAM_COLORS[p.team] || ['#333','#555'];
    return {
      pos,
      name: p.name,
      shortName: p.name.split('-').pop(),
      team: p.team,
      decade: p.decade,
      color: colors[0],
      color2: colors[1] || colors[0]
    };
  }).filter(Boolean);
}

const POSTER_W = 600, POSTER_H = 1100, POSTER_SCALE = 2;
const POSTER_BG_SRC = "data:image/png;base64,";

function drawCircularClip(ctx, cx, cy, radius) {
  ctx.beginPath();
  ctx.arc(cx, cy, radius, 0, Math.PI * 2);
  ctx.closePath();
  ctx.clip();
}

function drawRoundRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y);
  ctx.quadraticCurveTo(x + w, y, x + w, y + r);
  ctx.lineTo(x + w, y + h - r);
  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  ctx.lineTo(x + r, y + h);
  ctx.quadraticCurveTo(x, y + h, x, y + h - r);
  ctx.lineTo(x, y + r);
  ctx.quadraticCurveTo(x, y, x + r, y);
  ctx.closePath();
}

function drawRecordGroup(ctx, cx, topY, w, record, grade, tier, recColor) {
  const [wins = '0', losses = '82'] = String(record || '0-82').split('-');

  ctx.textBaseline = 'top';
  ctx.textAlign = 'left';
  ctx.fillStyle = '#ffffff';
  ctx.font = '900 24px -apple-system, "PingFang SC", sans-serif';
  ctx.fillText('我的完美阵容战绩', 58, topY);

  ctx.font = '900 92px Oswald, Impact, "Arial Black", sans-serif';
  ctx.fillText(wins, 58, topY + 38);
  const winsW = ctx.measureText(wins).width;
  ctx.fillText(' - ', 58 + winsW + 6, topY + 38);
  const dashW = ctx.measureText(' - ').width;
  ctx.fillStyle = '#8f8f8f';
  ctx.fillText(losses, 58 + winsW + dashW + 12, topY + 38);

  ctx.textAlign = 'right';
  ctx.fillStyle = recColor;
  ctx.font = '900 24px -apple-system, "PingFang SC", sans-serif';
  ctx.fillText(tier || '历史级强队', w - 58, topY);
  ctx.font = '900 108px Oswald, Impact, "Arial Black", sans-serif';
  ctx.fillText(grade || 'S', w - 58, topY + 40);
}

function drawPoster(ctx, w, h, players, record, grade, tier) {
  if (window._posterBgImg && window._posterBgImg.complete && window._posterBgImg.naturalWidth > 0) {
    ctx.drawImage(window._posterBgImg, 0, 0, w, h);
  } else {
    ctx.fillStyle = '#000000';
    ctx.fillRect(0, 0, w, h);
  }

  const wins = Number(String(record || '0-82').split('-')[0]);
  const recColor = record === '82-0' ? '#f4c351' : wins >= 70 ? '#f4c351' : wins >= 50 ? '#f39c12' : '#e74c3c';

  drawRecordGroup(ctx, w / 2, 170, w, record, grade, tier, recColor);

  const cardX = 52;
  const cardW = w - 104;
  const cardH = 82;
  const cardGap = 24;
  const startY = 330;
  players.forEach((p, i) => {
    const x = cardX;
    const y = startY + i * (cardH + cardGap);
    const cy = y + cardH / 2;
    const accent = p.color || '#2d76ca';

    ctx.fillStyle = 'rgba(0,0,0,0.86)';
    ctx.fillRect(x, y, cardW, cardH);
    ctx.lineWidth = 3;
    ctx.strokeStyle = accent;
    ctx.strokeRect(x, y, cardW, cardH);
    ctx.fillStyle = accent;
    ctx.fillRect(x, y, 8, cardH);

    ctx.fillStyle = accent;
    ctx.font = '900 30px Oswald, Impact, "Arial Black", sans-serif';
    ctx.textAlign = 'left';
    ctx.textBaseline = 'middle';
    ctx.fillText(p.pos || '', x + 28, cy);

    ctx.fillStyle = '#ffffff';
    ctx.font = '900 31px -apple-system, "PingFang SC", sans-serif';
    ctx.fillText(p.name, x + 108, cy);

    ctx.fillStyle = '#5d5d5d';
    ctx.font = '500 27px -apple-system, "PingFang SC", sans-serif';
    ctx.textAlign = 'right';
    ctx.fillText(teamCN(p.team), x + cardW - 30, cy - 16);
    ctx.font = '500 24px -apple-system, "PingFang SC", sans-serif';
    ctx.fillText(p.decade, x + cardW - 30, cy + 18);
  });

  ctx.textAlign = 'left';
  ctx.fillStyle = '#ffffff';
  ctx.font = '900 26px -apple-system, "PingFang SC", sans-serif';
  ctx.fillText('我的阵容名单', cardX, startY + 5 * (cardH + cardGap) + 8);
}

function loadPosterBackground() {
  return new Promise(resolve => {
    if (window._posterBgImg && window._posterBgImg.complete && window._posterBgImg.naturalWidth > 0) {
      resolve();
      return;
    }
    const img = new Image();
    img.onload = () => { window._posterBgImg = img; resolve(); };
    img.onerror = () => resolve();
    img.src = POSTER_BG_SRC;
  });
}

function createPosterCanvasAsync() {
  const players = getPosterPlayers();
  const recordEl = document.getElementById('finalRecord');
  const record = recordEl ? recordEl.textContent : '82-0';
  const canvas = document.getElementById('posterCanvas');
  canvas.width = POSTER_W * POSTER_SCALE;
  canvas.height = POSTER_H * POSTER_SCALE;
  const ctx = canvas.getContext('2d');
  ctx.scale(POSTER_SCALE, POSTER_SCALE);

  return loadPosterBackground().then(() => {
    const grade = game._posterGrade || '';
    const tier = game._posterTier || '';
    drawPoster(ctx, POSTER_W, POSTER_H, players, record, grade, tier);
    canvas._corsSafe = true;
    return canvas;
  });
}

function generatePoster() {
  createPosterCanvasAsync().then(canvas => {
    const dataURL = canvas.toDataURL('image/png');
    document.getElementById('posterPreviewImg').src = dataURL;
    document.getElementById('posterOverlay').style.display = 'flex';
  }).catch(err => {
    console.error('Poster generation failed:', err);
  });
}

function closePoster() {
  document.getElementById('posterOverlay').style.display = 'none';
}

function dataURLToBlob(dataURL) {
  const parts = dataURL.split(',');
  const mime = parts[0].match(/:(.*?);/)[1];
  const bytes = atob(parts[1]);
  const ab = new ArrayBuffer(bytes.length);
  const ia = new Uint8Array(ab);
  for (let i = 0; i < bytes.length; i++) ia[i] = bytes.charCodeAt(i);
  return new Blob([ab], { type: mime });
}

function sharePoster(btn) {
  const canvas = document.getElementById('posterCanvas');
  if (!canvas.width) return;
  const dataURL = canvas.toDataURL('image/png');
  const blob = dataURLToBlob(dataURL);
  if (blob.size === 0) return;

  const origText = btn.innerHTML;
  btn.innerHTML = '⏳ 上传中...';
  btn.disabled = true;

  const filename = 'poster_82_0_' + Date.now() + '.png';

  // Upload via colorbox bridge
  function doUpload() {
    return new Promise((resolve, reject) => {
      if (window.parent && window.parent !== window) {
        const callbackId = '_cb_up_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
        const timer = setTimeout(() => { cleanup(); reject(new Error('Upload timeout')); }, 30000);
        const handler = e => {
          const d = e.data;
          if (d && d.protocol === 'colorbox-ai-bridge' && d.type === 'oss.upload.callback' && d.payload && d.payload.callbackId === callbackId) {
            clearTimeout(timer); cleanup();
            d.payload.error ? reject(new Error(d.payload.error)) : resolve(d.payload.downloadUrl || '');
          }
        };
        const cleanup = () => window.removeEventListener('message', handler);
        window.addEventListener('message', handler);
        window.parent.postMessage({
          protocol: 'colorbox-ai-bridge', version: 1, direction: 'frame-to-host',
          type: 'oss.upload',
          payload: { file: blob, filename, callbackId }
        }, '*');
      } else {
        reject(new Error('No upload capability'));
      }
    });
  }

  doUpload().then(imageUrl => {
    const initialValue = {
      syncPost: true,
      appJsonV3: {
        activeTab: 'thread',
        data: { title: '', imageList: imageUrl ? [imageUrl] : [], content: '' }
      }
    };
    const postUrl = 'huputiyu://bbs/postImg?tagName=' + encodeURIComponent('82-0完美赛季') +
      '&tagId=148405' +
      '&topicName=' + encodeURIComponent('湿乎乎的话题') +
      '&topicId=177' +
      '&initialValue=' + encodeURIComponent(JSON.stringify(initialValue));
    safeNavigate(postUrl, '_self', 'poster_share');
    closePoster();
  }).catch(e => {
    console.warn('Poster upload failed', e);
  }).finally(() => {
    btn.innerHTML = origText;
    btn.disabled = false;
  });
}

